     1→/**
     2→ * Session Repository (T044) - Prisma Implementation
     3→ *
     4→ * Repository pattern for session lifecycle management, performance tracking,
     5→ * and analytics queries using Prisma ORM.
     6→ *
     7→ * Separation of Concerns from T043 ClassificationRepository:
     8→ * - T043: Write-heavy classification persistence (commands)
     9→ * - T044: Read-heavy session analytics and lifecycle management (queries)
    10→ *
    11→ * Key Responsibilities:
    12→ * - Session lifecycle management (create, update progress, complete, abort)
    13→ * - Batch processing support (multi-email sessions)
    14→ * - Performance metrics tracking
    15→ * - Error logging and retrieval
    16→ * - Analytics queries (by ID, status, date range, average times, failure rates)
    17→ */
    18→
    19→import { PrismaClient, Prisma } from '@prisma/client';
    20→import {
    21→  BatchSessionConfig,
    22→  ProgressUpdate,
    23→  SessionSummary,
    24→  EmailResult,
    25→  SessionDetails,
    26→  SessionStatus,
    27→  PerformanceMetrics,
    28→  BatchProgress,
    29→  SessionError,
    30→  DateRange,
    31→} from '../types/session-types';
    32→
    33→/**
    34→ * Session Repository using Prisma ORM
    35→ *
    36→ * Provides session lifecycle management with performance tracking,
    37→ * batch progress monitoring, and analytics queries.
    38→ */
    39→export class SessionRepository {
    40→  private readonly prisma: PrismaClient;
    41→  private readonly ownsPrisma: boolean;
    42→
    43→  /**
    44→   * Initialize session repository
    45→   *
    46→   * @param prisma - Optional Prisma client instance (creates default if not provided)
    47→   */
    48→  constructor(prisma?: PrismaClient) {
    49→    if (prisma) {
    50→      this.prisma = prisma;
    51→      this.ownsPrisma = false;
    52→    } else {
    53→      this.prisma = new PrismaClient();
    54→      this.ownsPrisma = true;
    55→    }
    56→  }
    57→
    58→  /**
    59→   * Validate and convert session ID from string to BigInt
    60→   *
    61→   * @param sessionId - Session ID as string
    62→   * @returns BigInt representation of session ID
    63→   * @throws {Error} If session ID format is invalid
    64→   */
    65→  private validateAndConvertSessionId(sessionId: string): bigint {
    66→    // Validate format (1-19 digits for safe BigInt conversion)
    67→    if (!/^\d{1,19}$/.test(sessionId)) {
    68→      throw new Error(`Invalid session ID format: ${sessionId}`);
    69→    }
    70→
    71→    try {
    72→      return BigInt(sessionId);
    73→    } catch {
    74→      throw new Error(`Failed to parse session ID: ${sessionId}`);
    75→    }
    76→  }
    77→
    78→  /**
    79→   * Validate progress update values
    80→   *
    81→   * @param update - Progress update with increment values
    82→   * @throws {Error} If any increment values are negative
    83→   */
    84→  private validateProgressUpdate(update: ProgressUpdate): void {
    85→    if (update.successCount !== undefined && update.successCount < 0) {
    86→      throw new Error('Success count increment must be non-negative');
    87→    }
    88→    if (update.errorCount !== undefined && update.errorCount < 0) {
    89→      throw new Error('Error count increment must be non-negative');
    90→    }
    91→    if (update.parallelStagesCount !== undefined && update.parallelStagesCount < 0) {
    92→      throw new Error('Parallel stages count increment must be non-negative');
    93→    }
    94→    if (update.databaseBatchOps !== undefined && update.databaseBatchOps < 0) {
    95→      throw new Error('Database batch operations increment must be non-negative');
    96→    }
    97→  }
    98→
    99→  /**
   100→   * Validate date range
   101→   *
   102→   * @param dateRange - Start and end dates
   103→   * @throws {Error} If date range is invalid
   104→   */
   105→  private validateDateRange(dateRange: DateRange): void {
   106→    if (dateRange.start > dateRange.end) {
   107→      throw new Error(
   108→        `Invalid date range: start (${dateRange.start.toISOString()}) must be before or equal to end (${dateRange.end.toISOString()})`
   109→      );
   110→    }
   111→  }
   112→
   113→  /**
   114→   * Create a new batch session with performance tracking
   115→   *
   116→   * Creates both the session record and associated metrics in a transaction.
   117→   * Supports multi-email batch processing.
   118→   *
   119→   * @param config - Batch session configuration
   120→   * @returns Session ID as string (safe representation of bigint)
   121→   * @throws {Error} If session creation fails
   122→   */
   123→  async createBatchSession(config: BatchSessionConfig): Promise<string> {
   124→    try {
   125→      const result = await this.prisma.$transaction(async (tx) => {
   126→        // Create session record
   127→        const session = await tx.classificationSession.create({
   128→          data: {
   129→            gmailId: config.gmailId,
   130→            pipelineVersion: config.pipelineVersion,
   131→            startedAt: new Date(),
   132→            status: 'in_progress',
   133→            triggeredBy: config.triggeredBy || 'system',
   134→            aiRoutingUsed: false,
   135→          },
   136→        });
   137→
   138→        // Create metrics record
   139→        await tx.classificationSessionMetrics.create({
   140→          data: {
   141→            sessionId: session.sessionId,
   142→            emailCount: config.batchSize,
   143→            successCount: 0,
   144→            errorCount: 0,
   145→            processingMode: config.processingMode,
   146→            batchSize: config.batchSize,
   147→          },
   148→        });
   149→
   150→        return session.sessionId.toString();
   151→      });
   152→
   153→      return result;
   154→    } catch (error) {
   155→      throw new Error(`Failed to create batch session: ${error instanceof Error ? error.message : String(error)}`);
   156→    }
   157→  }
   158→
   159→  /**
   160→   * Update session progress with atomic increments
   161→   *
   162→   * Increments success/error counts and other metrics atomically.
   163→   * Safe for concurrent updates from parallel processing.
   164→   *
   165→   * @param sessionId - Session identifier as string
   166→   * @param update - Progress update with incremental values
   167→   * @throws {Error} If update fails or session not found
   168→   */
   169→  async updateSessionProgress(sessionId: string, update: ProgressUpdate): Promise<void> {
   170→    this.validateProgressUpdate(update);
   171→
   172→    try {
   173→      const dbSessionId = this.validateAndConvertSessionId(sessionId);
   174→
   175→      // Build update data with atomic increments using proper Prisma type
   176→      const updateData: Prisma.ClassificationSessionMetricsUpdateInput = {
   177→        updatedAt: new Date(),
   178→      };
   179→
   180→      if (update.successCount !== undefined) {
   181→        updateData.successCount = { increment: update.successCount };
   182→      }
   183→      if (update.errorCount !== undefined) {
   184→        updateData.errorCount = { increment: update.errorCount };
   185→      }
   186→      if (update.parallelStagesCount !== undefined) {
   187→        updateData.parallelStagesCount = { increment: update.parallelStagesCount };
   188→      }
   189→      if (update.databaseBatchOps !== undefined) {
   190→        updateData.databaseBatchOps = { increment: update.databaseBatchOps };
   191→      }
   192→
   193→      await this.prisma.classificationSessionMetrics.update({
   194→        where: { sessionId: dbSessionId },
   195→        data: updateData,
   196→      });
   197→    } catch (error) {
   198→      throw new Error(
   199→        `Failed to update session progress for ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   200→      );
   201→    }
   202→  }
   203→
   204→  /**
   205→   * Complete a session with final performance metrics
   206→   *
   207→   * Updates session status to 'completed' and stores final performance metrics.
   208→   * Uses transaction to ensure both session and metrics are updated atomically.
   209→   *
   210→   * @param sessionId - Session identifier as string
   211→   * @param summary - Session summary with performance metrics
   212→   * @throws {Error} If completion fails
   213→   */
   214→  async completeSession(sessionId: string, summary: SessionSummary): Promise<void> {
   215→    try {
   216→      const dbSessionId = this.validateAndConvertSessionId(sessionId);
   217→
   218→      await this.prisma.$transaction(async (tx) => {
   219→        // Update session record
   220→        await tx.classificationSession.update({
   221→          where: { sessionId: dbSessionId },
   222→          data: {
   223→            completedAt: new Date(),
   224→            status: 'completed',
   225→            finalCategoryCode: summary.finalCategoryCode || null,
   226→            finalConfidence: summary.finalConfidence ? new Prisma.Decimal(summary.finalConfidence) : null,
   227→            finalRationale: summary.finalRationale || null,
   228→          },
   229→        });
   230→
   231→        // Update metrics record
   232→        await tx.classificationSessionMetrics.update({
   233→          where: { sessionId: dbSessionId },
   234→          data: {
   235→            totalDurationMs: summary.totalDurationMs,
   236→            avgEmailDurationMs: summary.avgEmailDurationMs ? new Prisma.Decimal(summary.avgEmailDurationMs) : null,
   237→            peakMemoryMb: summary.peakMemoryMb ? new Prisma.Decimal(summary.peakMemoryMb) : null,
   238→            updatedAt: new Date(),
   239→          },
   240→        });
   241→      });
   242→    } catch (error) {
   243→      throw new Error(
   244→        `Failed to complete session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   245→      );
   246→    }
   247→  }
   248→
   249→  /**
   250→   * Abort a session with reason
   251→   *
   252→   * Marks session as 'aborted' and records the reason.
   253→   *
   254→   * @param sessionId - Session identifier as string
   255→   * @param reason - Reason for aborting
   256→   * @throws {Error} If abort fails
   257→   */
   258→  async abortSession(sessionId: string, reason: string): Promise<void> {
   259→    try {
   260→      const dbSessionId = this.validateAndConvertSessionId(sessionId);
   261→
   262→      await this.prisma.classificationSession.update({
   263→        where: { sessionId: dbSessionId },
   264→        data: {
   265→          status: 'aborted',
   266→          finalRationale: reason,
   267→          completedAt: new Date(),
   268→        },
   269→      });
   270→    } catch (error) {
   271→      throw new Error(
   272→        `Failed to abort session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   273→      );
   274→    }
   275→  }
   276→
   277→  /**
   278→   * Record result for individual email in batch
   279→   *
   280→   * Increments success/error counts and logs errors for failed emails.
   281→   * Uses transaction to ensure atomic updates.
   282→   *
   283→   * @param sessionId - Session identifier as string
   284→   * @param emailId - Email identifier
   285→   * @param result - Email processing result
   286→   * @throws {Error} If recording fails
   287→   */
   288→  async recordEmailResult(sessionId: string, emailId: string, result: EmailResult): Promise<void> {
   289→    try {
   290→      const dbSessionId = this.validateAndConvertSessionId(sessionId);
   291→
   292→      await this.prisma.$transaction(async (tx) => {
   293→        // Update metrics
   294→        if (result.success) {
   295→          await tx.classificationSessionMetrics.update({
   296→            where: { sessionId: dbSessionId },
   297→            data: {
   298→              successCount: { increment: 1 },
   299→              updatedAt: new Date(),
   300→            },
   301→          });
   302→        } else {
   303→          // Increment error count
   304→          await tx.classificationSessionMetrics.update({
   305→            where: { sessionId: dbSessionId },
   306→            data: {
   307→              errorCount: { increment: 1 },
   308→              updatedAt: new Date(),
   309→            },
   310→          });
   311→
   312→          // Log error
   313→          if (result.error) {
   314→            await tx.classificationSessionError.create({
   315→              data: {
   316→                sessionId: dbSessionId,
   317→                emailId: emailId,
   318→                errorType: result.error.type,
   319→                errorMessage: result.error.message,
   320→                stackTrace: result.error.stackTrace || null,
   321→              },
   322→            });
   323→          }
   324→        }
   325→      });
   326→    } catch (error) {
   327→      throw new Error(
   328→        `Failed to record email result for ${emailId}: ${error instanceof Error ? error.message : String(error)}`
   329→      );
   330→    }
   331→  }
   332→
   333→  /**
   334→   * Get batch progress for a session
   335→   *
   336→   * Calculates progress percentage and completion status.
   337→   * Optimized to use single query instead of separate metrics + session queries.
   338→   *
   339→   * @param sessionId - Session identifier as string
   340→   * @returns Batch progress summary
   341→   * @throws {Error} If session not found
   342→   */
   343→  async getBatchProgress(sessionId: string): Promise<BatchProgress> {
   344→    const dbSessionId = this.validateAndConvertSessionId(sessionId);
   345→
   346→    // Optimized: Single query with include instead of two separate queries
   347→    const session = await this.prisma.classificationSession.findUnique({
   348→      where: { sessionId: dbSessionId },
   349→      include: { metrics: true },
   350→    });
   351→
   352→    if (!session || !session.metrics) {
   353→      throw new Error(`Session not found: ${sessionId}`);
   354→    }
   355→
   356→    const metrics = session.metrics;
   357→    const totalProcessed = metrics.successCount + metrics.errorCount;
   358→    const progressPercentage = metrics.emailCount > 0 ? Math.round((totalProcessed / metrics.emailCount) * 100) : 0;
   359→
   360→    return {
   361→      sessionId: sessionId,
   362→      totalEmails: metrics.emailCount,
   363→      successCount: metrics.successCount,
   364→      errorCount: metrics.errorCount,
   365→      progressPercentage: progressPercentage,
   366→      isComplete: session.status === 'completed' || session.status === 'aborted',
   367→      status: session.status as SessionStatus,
   368→    };
   369→  }
   370→
   371→  /**
   372→   * Find session by ID with full details including metrics
   373→   *
   374→   * @param sessionId - Session identifier as string
   375→   * @returns Session details with metrics or null if not found
   376→   */
   377→  async findSessionById(sessionId: string): Promise<SessionDetails | null> {
   378→    const dbSessionId = this.validateAndConvertSessionId(sessionId);
   379→
   380→    const session = await this.prisma.classificationSession.findUnique({
   381→      where: { sessionId: dbSessionId },
   382→      include: {
   383→        metrics: true,
   384→      },
   385→    });
   386→
   387→    if (!session) {
   388→      return null;
   389→    }
   390→
   391→    return this.mapToSessionDetails(session);
   392→  }
   393→
   394→  /**
   395→   * Find all active (in-progress) sessions
   396→   *
   397→   * @returns Array of active session summaries
   398→   */
   399→  async findActiveSessions(): Promise<SessionDetails[]> {
   400→    const sessions = await this.prisma.classificationSession.findMany({
   401→      where: { status: 'in_progress' },
   402→      orderBy: { startedAt: 'desc' },
   403→      include: {
   404→        metrics: true,
   405→      },
   406→    });
   407→
   408→    return sessions.map((s) => this.mapToSessionDetails(s));
   409→  }
   410→
   411→  /**
   412→   * Find sessions by status
   413→   *
   414→   * @param status - Session status to filter by
   415→   * @returns Array of sessions with matching status
   416→   */
   417→  async findSessionsByStatus(status: SessionStatus): Promise<SessionDetails[]> {
   418→    const sessions = await this.prisma.classificationSession.findMany({
   419→      where: { status: status },
   420→      orderBy: { startedAt: 'desc' },
   421→      include: {
   422→        metrics: true,
   423→      },
   424→    });
   425→
   426→    return sessions.map((s) => this.mapToSessionDetails(s));
   427→  }
   428→
   429→  /**
   430→   * Find sessions within date range
   431→   *
   432→   * @param dateRange - Start and end dates (inclusive)
   433→   * @returns Array of sessions in date range
   434→   */
   435→  async findSessionsByDateRange(dateRange: DateRange): Promise<SessionDetails[]> {
   436→    this.validateDateRange(dateRange);
   437→
   438→    const sessions = await this.prisma.classificationSession.findMany({
   439→      where: {
   440→        startedAt: {
   441→          gte: dateRange.start,
   442→          lte: dateRange.end,
   443→        },
   444→      },
   445→      orderBy: { startedAt: 'desc' },
   446→      include: {
   447→        metrics: true,
   448→      },
   449→    });
   450→
   451→    return sessions.map((s) => this.mapToSessionDetails(s));
   452→  }
   453→
   454→  /**
   455→   * Get performance metrics for a session
   456→   *
   457→   * @param sessionId - Session identifier as string
   458→   * @returns Performance metrics
   459→   * @throws {Error} If metrics not found
   460→   */
   461→  async getSessionPerformanceStats(sessionId: string): Promise<PerformanceMetrics> {
   462→    const dbSessionId = this.validateAndConvertSessionId(sessionId);
   463→
   464→    const metrics = await this.prisma.classificationSessionMetrics.findUnique({
   465→      where: { sessionId: dbSessionId },
   466→    });
   467→
   468→    if (!metrics) {
   469→      throw new Error(`Session metrics not found for session: ${sessionId}`);
   470→    }
   471→
   472→    return {
   473→      emailCount: metrics.emailCount,
   474→      successCount: metrics.successCount,
   475→      errorCount: metrics.errorCount,
   476→      processingMode: metrics.processingMode as 'sequential' | 'parallel' | 'batch' | null,
   477→      batchSize: metrics.batchSize,
   478→      totalDurationMs: metrics.totalDurationMs,
   479→      avgEmailDurationMs: metrics.avgEmailDurationMs ? metrics.avgEmailDurationMs.toNumber() : null,
   480→      parallelStagesCount: metrics.parallelStagesCount,
   481→      databaseBatchOps: metrics.databaseBatchOps,
   482→      peakMemoryMb: metrics.peakMemoryMb ? metrics.peakMemoryMb.toNumber() : null,
   483→      createdAt: metrics.createdAt,
   484→      updatedAt: metrics.updatedAt,
   485→    };
   486→  }
   487→
   488→  /**
   489→   * Calculate average processing time across sessions in date range
   490→   *
   491→   * @param dateRange - Start and end dates (inclusive)
   492→   * @returns Average email processing time in milliseconds
   493→   */
   494→  async getAverageProcessingTime(dateRange: DateRange): Promise<number> {
   495→    this.validateDateRange(dateRange);
   496→
   497→    const sessions = await this.prisma.classificationSession.findMany({
   498→      where: {
   499→        startedAt: {
   500→          gte: dateRange.start,
   501→          lte: dateRange.end,
   502→        },
   503→      },
   504→      include: {
   505→        metrics: true,
   506→      },
   507→    });
   508→
   509→    if (sessions.length === 0) {
   510→      return 0;
   511→    }
   512→
   513→    const avgTimes = sessions
   514→      .map((s) => s.metrics?.avgEmailDurationMs?.toNumber())
   515→      .filter((time): time is number => time !== undefined && time !== null);
   516→
   517→    if (avgTimes.length === 0) {
   518→      return 0;
   519→    }
   520→
   521→    const sum = avgTimes.reduce((acc, time) => acc + time, 0);
   522→    return sum / avgTimes.length;
   523→  }
   524→
   525→  /**
   526→   * Calculate failure rate across sessions in date range
   527→   *
   528→   * @param dateRange - Start and end dates (inclusive)
   529→   * @returns Failure rate as percentage (0-100)
   530→   */
   531→  async getFailureRate(dateRange: DateRange): Promise<number> {
   532→    this.validateDateRange(dateRange);
   533→
   534→    const sessions = await this.prisma.classificationSession.findMany({
   535→      where: {
   536→        startedAt: {
   537→          gte: dateRange.start,
   538→          lte: dateRange.end,
   539→        },
   540→      },
   541→      include: {
   542→        metrics: true,
   543→      },
   544→    });
   545→
   546→    if (sessions.length === 0) {
   547→      return 0;
   548→    }
   549→
   550→    let totalEmails = 0;
   551→    let totalErrors = 0;
   552→
   553→    for (const session of sessions) {
   554→      if (session.metrics) {
   555→        totalEmails += session.metrics.emailCount;
   556→        totalErrors += session.metrics.errorCount;
   557→      }
   558→    }
   559→
   560→    if (totalEmails === 0) {
   561→      return 0;
   562→    }
   563→
   564→    return (totalErrors / totalEmails) * 100;
   565→  }
   566→
   567→  /**
   568→   * Get all errors for a session
   569→   *
   570→   * @param sessionId - Session identifier as string
   571→   * @returns Array of session errors
   572→   */
   573→  async getSessionErrors(sessionId: string): Promise<SessionError[]> {
   574→    const dbSessionId = this.validateAndConvertSessionId(sessionId);
   575→
   576→    const errors = await this.prisma.classificationSessionError.findMany({
   577→      where: { sessionId: dbSessionId },
   578→      orderBy: { occurredAt: 'desc' },
   579→    });
   580→
   581→    return errors.map((e) => ({
   582→      errorId: e.errorId.toString(),
   583→      sessionId: e.sessionId.toString(),
   584→      emailId: e.emailId,
   585→      errorType: e.errorType,
   586→      errorMessage: e.errorMessage,
   587→      stackTrace: e.stackTrace,
   588→      occurredAt: e.occurredAt,
   589→    }));
   590→  }
   591→
   592→  /**
   593→   * Map Prisma session record to SessionDetails type
   594→   *
   595→   * @param session - Prisma session record with metrics
   596→   * @returns SessionDetails object
   597→   */
   598→  private mapToSessionDetails(
   599→    session: Prisma.ClassificationSessionGetPayload<{
   600→      include: { metrics: true };
   601→    }>
   602→  ): SessionDetails {
   603→    return {
   604→      sessionId: session.sessionId.toString(),
   605→      gmailId: session.gmailId,
   606→      pipelineVersion: session.pipelineVersion,
   607→      startedAt: session.startedAt,
   608→      completedAt: session.completedAt,
   609→      status: session.status as SessionStatus,
   610→      triggeredBy: session.triggeredBy,
   611→      aiRoutingUsed: session.aiRoutingUsed,
   612→      finalCategoryCode: session.finalCategoryCode,
   613→      finalConfidence: session.finalConfidence ? session.finalConfidence.toNumber() : null,
   614→      finalRationale: session.finalRationale,
   615→      metrics: session.metrics
   616→        ? {
   617→            emailCount: session.metrics.emailCount,
   618→            successCount: session.metrics.successCount,
   619→            errorCount: session.metrics.errorCount,
   620→            processingMode: session.metrics.processingMode as 'sequential' | 'parallel' | 'batch' | null,
   621→            batchSize: session.metrics.batchSize,
   622→            totalDurationMs: session.metrics.totalDurationMs,
   623→            avgEmailDurationMs: session.metrics.avgEmailDurationMs
   624→              ? session.metrics.avgEmailDurationMs.toNumber()
   625→              : null,
   626→            parallelStagesCount: session.metrics.parallelStagesCount,
   627→            databaseBatchOps: session.metrics.databaseBatchOps,
   628→            peakMemoryMb: session.metrics.peakMemoryMb ? session.metrics.peakMemoryMb.toNumber() : null,
   629→            createdAt: session.metrics.createdAt,
   630→            updatedAt: session.metrics.updatedAt,
   631→          }
   632→        : null,
   633→    };
   634→  }
   635→
   636→  /**
   637→   * Close the Prisma client connection
   638→   *
   639→   * Only closes if using default Prisma instance (not externally provided).
   640→   */
   641→  async close(): Promise<void> {
   642→    if (this.ownsPrisma) {
   643→      await this.prisma.$disconnect();
   644→    }
   645→  }
   646→}
