        digestType: 'daily',
        dateRange: { start: new Date(), end: new Date() },
        recipientEmail: 'user@example.com',
      });

      // Should be sorted by priority (using categoryId as fallback): newsletters (1), financial (2), social (3)
      expect(digest.categories[0].categoryName).toBe('newsletters');
      expect(digest.categories[1].categoryName).toBe('financial');
      expect(digest.categories[2].categoryName).toBe('social');
