toolUseResult.originalFile:
/**
 * Classification Results Persistence Layer (T043) - Prisma Implementation
 *
 * Repository pattern for classification results persistence using Prisma ORM:
 * - Classification session management (create, update, complete)
 * - Classification results with explainability traces
 * - Score breakdown persistence
 * - Attribute context storage
 * - Multi-label classification support
 * - Domain signal resolutions
 * - Transaction-safe batch operations
 *
 * Benefits of Prisma ORM:
 * - Type-safe database queries with auto-generated types
 * - Built-in transaction handling for complex multi-table operations
 * - Automatic JSON serialization/deserialization for explainability data
 * - Connection pooling and query optimization
 * - SQL injection protection via parameterized queries
 */

import { PrismaClient, Prisma } from '@prisma/client';
import { ClassificationResult, ClassificationSession, AttributeContext } from '@gmail-automation/classification-engine';

/**
 * Domain signal resolution data structure
 */
export interface DomainSignalData {
  domain: string;
  signalType: 'hard_assertion' | 'strong_indicator' | 'weak_signal';
  matchedCategoryId: number | null;
  confidenceLevel?: string;
  domainType?: string;
}

/**
 * Classification Repository using Prisma ORM
 *
 * Provides type-safe classification results persistence with automatic transaction
 * handling, connection pooling, and explainability trace integrity.
 */
export class ClassificationRepository {
  private readonly prisma: PrismaClient;
  private readonly ownsPrisma: boolean;
  private categoryCache: Map<string, number> | null = null;

  /**
   * Initialize classification repository
   *
   * @param prisma - Optional Prisma client instance (creates default if not provided)
   */
  constructor(prisma?: PrismaClient) {
    if (prisma) {
      this.prisma = prisma;
      this.ownsPrisma = false;
    } else {
      this.prisma = new PrismaClient();
      this.ownsPrisma = true;
    }
  }

  /**
   * Initialize category cache from database
   *
   * Loads all active categories into memory for fast lookup by code.
   * Called automatically on first use of getCategoryIdFromCode().
   *
   * @throws {Error} If category loading fails
   */
  private async initializeCategoryCache(): Promise<void> {
    try {
      const categories = await this.prisma.category.findMany({
        where: { active: true },
        select: { code: true, categoryId: true },
      });

      this.categoryCache = new Map(categories.map((cat) => [cat.code, cat.categoryId]));
    } catch (error) {
      throw new Error(`Failed to load category cache: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Create a new classification session
   *
   * @param session - ClassificationSession object
   * @param gmailId - Gmail message ID being classified
   * @returns Database session ID as string (safe representation of bigint)
   * @throws {Error} If session creation fails
   */
  async createSession(session: ClassificationSession, gmailId: string): Promise<string> {
    try {
      const result = await this.prisma.classificationSession.create({
        data: {
          gmailId: gmailId,
          pipelineVersion: session.configVersion,
          startedAt: session.startedAt,
          status: 'in_progress',
          triggeredBy: 'system',
          aiRoutingUsed: false,
        },
      });

      return result.sessionId.toString();
    } catch (error) {
      throw new Error(
        `Failed to create classification session: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Complete a classification session
   *
   * @param sessionId - Session identifier as string (from createSession)
   * @param finalCategoryId - Final category ID selected
   * @param confidence - Final confidence score
   * @param rationale - Final decision rationale
   * @throws {Error} If session update fails
   */
  async completeSession(
    sessionId: string,
    finalCategoryId: number,
    confidence: number,
    rationale: string
  ): Promise<void> {
    try {
      // Convert string session ID to BigInt for database query
      const dbSessionId = BigInt(sessionId);

      await this.prisma.classificationSession.update({
        where: { sessionId: dbSessionId },
        data: {
          completedAt: new Date(),
          finalCategoryId: finalCategoryId,
          finalConfidence: new Prisma.Decimal(confidence),
          finalRationale: rationale,
          status: 'completed',
        },
      });
    } catch (error) {
      throw new Error(
        `Failed to complete session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Save complete classification result with explainability trace
   *
   * Uses Prisma transaction to ensure atomicity across multiple tables:
   * - classification_stage (10 pipeline stages)
   * - stage_category_eval (per-category evaluations)
   * - session_categories (multi-label support)
   * - detected_attributes (attribute context)
   * - extracted_features (AI feature extraction data, if AI was used)
   * - domain_signal_resolutions (domain signals)
   *
   * @param result - ClassificationResult with explainability trace
   * @param sessionId - Session identifier as string (from createSession)
   * @throws {Error} If save fails (rolls back entire transaction)
   */
  async saveClassificationResult(result: ClassificationResult, sessionId: string): Promise<void> {
    try {
      const dbSessionId = BigInt(sessionId);

      await this.prisma.$transaction(async (tx) => {
        await this.saveClassificationResultInTransaction(tx, result, dbSessionId);
      });
    } catch (error) {
      throw new Error(
        `Failed to save classification result for email ${result.emailId}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Internal method to save classification result within a transaction
   *
   * Extracted to allow both single and batch saves to share the same logic
   * while maintaining proper transaction boundaries.
   *
   * @param tx - Prisma transaction client
   * @param result - ClassificationResult with explainability trace
   * @param sessionId - Session identifier as bigint
   * @throws {Error} If save fails (caller should handle)
   */
  private async saveClassificationResultInTransaction(
    tx: Prisma.TransactionClient,
    result: ClassificationResult,
    sessionId: bigint
  ): Promise<void> {
    // 1. Create classification stages (10 pipeline stages: hard assertions through action determination)
    const stageData = this.buildStageData(result, sessionId);
    let stageRecords: Array<{ stageId: bigint; stageOrder: number }> = [];
    if (stageData.length > 0) {
      await tx.classificationStage.createMany({ data: stageData });

      // Retrieve created stage records to get stage IDs for AI feature extraction
      stageRecords = await tx.classificationStage.findMany({
        where: { sessionId: sessionId },
        select: { stageId: true, stageOrder: true },
        orderBy: { stageOrder: 'asc' },
      });
    }

    // 2. Create stage category evaluations (score breakdown for each category)
    const categoryEvalData = await this.buildCategoryEvalData(result, sessionId);
    if (categoryEvalData.length > 0) {
      await tx.stageCategoryEval.createMany({ data: categoryEvalData });
    }

    // 3. Create session categories (multi-label support)
    const sessionCategoryData = await this.buildSessionCategoryData(result, sessionId);
    if (sessionCategoryData.length > 0) {
      await tx.sessionCategory.createMany({ data: sessionCategoryData });
    }

    // 4. Create detected attributes (attribute context)
    const attributeData = this.buildAttributeData(result.attributeContext, sessionId);
    if (attributeData.length > 0) {
      await tx.detectedAttribute.createMany({ data: attributeData });
    }

    // 5. Create extracted features (AI feature extraction data)
    // Only persist if AI routing was used and we have feature extraction data
    if (result.aiRoutingUsed && stageRecords.length > 0) {
      const extractedFeatureData = this.buildExtractedFeatureData(result, stageRecords);
      if (extractedFeatureData.length > 0) {
        await tx.extractedFeature.createMany({ data: extractedFeatureData });
      }
    }
  }

  /**
   * Save attribute context separately
   *
   * @param context - AttributeContext with detected attributes
   * @param sessionId - Session identifier as string (from createSession)
   * @throws {Error} If save fails
   */
  async saveAttributeContext(context: AttributeContext, sessionId: string): Promise<void> {
    try {
      const dbSessionId = BigInt(sessionId);
      const attributeData = this.buildAttributeData(context, dbSessionId);
      if (attributeData.length > 0) {
        await this.prisma.detectedAttribute.createMany({ data: attributeData });
      }
    } catch (error) {
      throw new Error(`Failed to save attribute context: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Save domain signal resolutions
   *
   * @param signals - Array of domain signal resolutions
   * @param sessionId - Session identifier as string (from createSession)
   * @throws {Error} If save fails
   */
  async saveDomainSignals(signals: DomainSignalData[], sessionId: string): Promise<void> {
    if (signals.length === 0) {
      return;
    }

    try {
      const dbSessionId = BigInt(sessionId);
      await this.prisma.domainSignalResolution.createMany({
        data: signals.map((signal) => ({
          sessionId: dbSessionId,
          domain: signal.domain,
          signalType: signal.signalType,
          matchedCategoryId: signal.matchedCategoryId,
          confidenceLevel: signal.confidenceLevel || null,
          domainType: signal.domainType || null,
          createdAt: new Date(),
        })),
      });
    } catch (error) {
      throw new Error(`Failed to save domain signals: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Batch save multiple classification results
   *
   * Wraps all saves in a single outer transaction for atomicity.
   * Either all results are saved or none are (all-or-nothing semantics).
   *
   * @param results - Array of ClassificationResult objects
   * @param sessionId - Session identifier as string (from createSession)
   * @throws {Error} If batch save fails (entire batch is rolled back)
   */
  async batchSaveResults(results: ClassificationResult[], sessionId: string): Promise<void> {
    if (results.length === 0) {
      return;
    }

    try {
      const dbSessionId = BigInt(sessionId);

      // Wrap entire batch in outer transaction for atomicity (T043.5)
      await this.prisma.$transaction(async (tx) => {
        for (const result of results) {
          await this.saveClassificationResultInTransaction(tx, result, dbSessionId);
        }
      });
    } catch (error) {
      throw new Error(
        `Failed to batch save classification results: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Build classification stage data from explainability trace
   */
  private buildStageData(
    result: ClassificationResult,
    sessionId: bigint
  ): Array<Prisma.ClassificationStageCreateManyInput> {
    const stages: Array<Prisma.ClassificationStageCreateManyInput> = [];
    const trace = result.explainabilityTrace;

    // Map pipeline stages to database records
    const stageMapping = [
      { order: 1, type: 'hard_assertions', data: trace.hardAssertions },
      { order: 2, type: 'strong_indicators', data: trace.strongIndicators },
      { order: 3, type: 'rule_scoring', data: trace.ruleScoring },
      { order: 4, type: 'attribute_detection', data: trace.attributeDetection },
      { order: 5, type: 'attribute_influence', data: trace.attributeInfluence },
      { order: 6, type: 'disambiguation', data: trace.disambiguation },
      { order: 7, type: 'multi_label_selection', data: trace.multiLabelSelection },
      { order: 8, type: 'ai_routing', data: trace.aiRouting },
      { order: 9, type: 'final_decision', data: { reason: trace.finalDecisionReason } },
      {
        order: 10,
        type: 'action_determination',
        data: {
          determinedActions: result.determinedActions || [],
          actionReasoning: result.finalClassificationSummary?.determinedActions
            ? `Actions: ${result.finalClassificationSummary.determinedActions.join(', ')}`
            : 'No actions determined',
        },
      },
    ];

    for (const stage of stageMapping) {
      stages.push({
        sessionId: sessionId,
        stageOrder: stage.order,
        stageType: stage.type,
        startedAt: new Date(),
        endedAt: new Date(),
        features: stage.data as Prisma.InputJsonValue,
        keywords: [],
        passedToNext: true,
      });
    }

    return stages;
  }

  /**
   * Build stage category evaluation data from score breakdown
   */
  private async buildCategoryEvalData(
    result: ClassificationResult,
    sessionId: bigint
  ): Promise<Array<Prisma.StageCategoryEvalCreateManyInput>> {
    const evaluations: Array<Prisma.StageCategoryEvalCreateManyInput> = [];
    const scoreBreakdown = result.scoreBreakdown;

    // Extract category scores and create evaluations
    for (const [category, scores] of Object.entries(scoreBreakdown.categoryScores || {})) {
      try {
        const categoryId = await this.getCategoryIdFromCode(category);
        evaluations.push({
          stageId: sessionId, // Simplified: using session_id as stage_id for MVP
          categoryId: categoryId,
          decision: result.selectedLabels.some((label) => label.category === category) ? 'positive' : 'candidate',
          score: scores as unknown as Prisma.InputJsonValue,
          confidence: new Prisma.Decimal(scores.finalScore || 0),
          scoringComponents: scores as unknown as Prisma.InputJsonValue,
          keywords: [],
          createdAt: new Date(),
        });
      } catch (error) {
        // Log warning and skip unknown category (graceful degradation)
        console.warn(
          `Skipping category evaluation for unknown category '${category}': ${error instanceof Error ? error.message : String(error)}`
        );
      }
    }

    return evaluations;
  }

  /**
   * Build session category data (multi-label support)
   */
  private async buildSessionCategoryData(
    result: ClassificationResult,
    sessionId: bigint
  ): Promise<Array<Prisma.SessionCategoryCreateManyInput>> {
    const categories: Array<Prisma.SessionCategoryCreateManyInput> = [];

    for (const label of result.selectedLabels) {
      try {
        const categoryId = await this.getCategoryIdFromCode(label.category);
        const subtypeId = label.subtype ? await this.getCategoryIdFromCode(label.subtype) : null;

        categories.push({
          sessionId: sessionId,
          categoryId: categoryId,
          subtypeId: subtypeId,
          isPrimary: label.isPrimary,
          confidence: new Prisma.Decimal(label.confidence),
          categoryScore: new Prisma.Decimal(label.score),
          hardAssertion: false, // TODO: Extract from explainability trace
          aiClassified: result.aiRoutingUsed,
          scoringTrace: result.scoreBreakdown as unknown as Prisma.InputJsonValue,
          labelOrder: label.labelOrder,
          createdAt: new Date(),
        });
      } catch (error) {
        // Log warning and skip unknown category (graceful degradation)
        console.warn(
          `Skipping session category for unknown category '${label.category}': ${error instanceof Error ? error.message : String(error)}`
        );
      }
    }

    return categories;
  }

  /**
   * Build detected attribute data from attribute context
   *
   * Maps attribute context to database records with complete detection metadata,
   * influence tracking, and temporal signals. Handles:
   * - Urgency levels with detection metadata
   * - Domain attributes with influence tracking
   * - Structural patterns with evidence
   * - Temporal signals (NEW: T043.4)
   * - Influence applications with score impacts (NEW: T043.4)
   * - Derived attributes (NEW: T043.4)
   *
   * @param context - AttributeContext with detected attributes and metadata
   * @param sessionId - Session identifier as bigint
   * @returns Array of detected attribute records for database insertion
   */
  private buildAttributeData(
    context: AttributeContext,
    sessionId: bigint
  ): Array<Prisma.DetectedAttributeCreateManyInput> {
    const attributes: Array<Prisma.DetectedAttributeCreateManyInput> = [];

    // Helper to extract detection metadata
    const getDetectionMetadata = (attributeKey: string) => {
      return context.detectionMetadata?.[attributeKey];
    };

    // Helper to find influence applications for an attribute
    const getInfluenceData = (attributeName: string) => {
      const influences = context.influenceApplications?.filter((app) => app.attributeUsed === attributeName) || [];
      const categoriesInfluenced = influences.map((app) => app.targetCategory);
      const totalBonus = influences.reduce((sum, app) => sum + app.scoreImpact, 0);
      const primaryRole = influences.length > 0 ? influences[0].roleType : 'NEUTRAL';
      return { categoriesInfluenced, totalBonus, primaryRole };
    };

    // 1. Add urgency attribute
    const urgencyMetadata = getDetectionMetadata('urgency');
    const urgencyInfluence = getInfluenceData('urgency');
    attributes.push({
      sessionId: sessionId,
      attributeName: 'urgency',
      attributeValue: context.urgency,
      detectionMethod: urgencyMetadata?.detectionMethod || 'rule',
      detectionEvidence: urgencyMetadata?.evidence || `Urgency level: ${context.urgency}`,
      influenceRole: urgencyInfluence.primaryRole,
      categoriesInfluenced: urgencyInfluence.categoriesInfluenced,
      totalBonusApplied: new Prisma.Decimal(urgencyInfluence.totalBonus),
      createdAt: new Date(),
    });

    // 2. Add domain attributes
    for (const domain of context.domains) {
      const domainKey = `domain:${domain}`;
      const domainMetadata = getDetectionMetadata(domainKey);
      const domainInfluence = getInfluenceData(domainKey);

      attributes.push({
        sessionId: sessionId,
        attributeName: domainKey,
        attributeValue: domain,
        detectionMethod: domainMetadata?.detectionMethod || 'domainLookup',
        detectionEvidence: domainMetadata?.evidence || `Domain ${domain} detected in email`,
        influenceRole: domainInfluence.primaryRole,
        categoriesInfluenced: domainInfluence.categoriesInfluenced,
        totalBonusApplied: new Prisma.Decimal(domainInfluence.totalBonus),
        createdAt: new Date(),
      });
    }

    // 3. Add structural pattern attributes
    for (const pattern of context.structuralPatterns) {
      const patternKey = `pattern:${pattern}`;
      const patternMetadata = getDetectionMetadata(patternKey);
      const patternInfluence = getInfluenceData(patternKey);

      attributes.push({
        sessionId: sessionId,
        attributeName: patternKey,
        attributeValue: pattern,
        detectionMethod: patternMetadata?.detectionMethod || 'pattern',
        detectionEvidence: patternMetadata?.evidence || `Structural pattern ${pattern} matched`,
        influenceRole: patternInfluence.primaryRole,
        categoriesInfluenced: patternInfluence.categoriesInfluenced,
        totalBonusApplied: new Prisma.Decimal(patternInfluence.totalBonus),
        createdAt: new Date(),
      });
    }

    // 4. Add temporal signal attributes (NEW: T043.4)
    for (const signal of context.temporalSignals) {
      const signalKey = `temporal:${signal}`;
      const signalMetadata = getDetectionMetadata(signalKey);
      const signalInfluence = getInfluenceData(signalKey);

      attributes.push({
        sessionId: sessionId,
        attributeName: signalKey,
        attributeValue: signal,
        detectionMethod: signalMetadata?.detectionMethod || 'temporalAnalysis',
        detectionEvidence:
          signalMetadata?.evidence || `Temporal signal ${signal} detected (e.g., time-sensitive keywords, deadlines)`,
        influenceRole: signalInfluence.primaryRole,
        categoriesInfluenced: signalInfluence.categoriesInfluenced,
        totalBonusApplied: new Prisma.Decimal(signalInfluence.totalBonus),
        createdAt: new Date(),
      });
    }

    // 5. Add derived attributes (NEW: T043.4)
    // Derived attributes are computed from other attributes (e.g., "is_self_sent" derived from from/to comparison)
    for (const [derivedKey, derivedResult] of Object.entries(context.derivedAttributes || {})) {
      const derivedInfluence = getInfluenceData(derivedKey);

      attributes.push({
        sessionId: sessionId,
        attributeName: derivedKey,
        attributeValue: String(derivedResult.calculatedValue),
        detectionMethod: 'derived',
        detectionEvidence: `Derived from: ${derivedResult.sourceAttributes.join(', ')} via ${derivedResult.derivationLogic}`,
        influenceRole: derivedInfluence.primaryRole,
        categoriesInfluenced: derivedInfluence.categoriesInfluenced,
        totalBonusApplied: new Prisma.Decimal(derivedInfluence.totalBonus),
        createdAt: new Date(),
      });
    }

    // 6. Add influence applications that don't map to specific detected attributes (NEW: T043.4)
    // Some influence applications may reference attributes not explicitly in the detected lists
    // (e.g., attribute combinations, context-dependent influences)
    const coveredAttributes = new Set([
      'urgency',
      ...context.domains.map((d) => `domain:${d}`),
      ...context.structuralPatterns.map((p) => `pattern:${p}`),
      ...context.temporalSignals.map((s) => `temporal:${s}`),
      ...Object.keys(context.derivedAttributes || {}),
    ]);

    for (const influence of context.influenceApplications || []) {
      if (!coveredAttributes.has(influence.attributeUsed)) {
        // This is an influence from an attribute not explicitly tracked above
        // (e.g., attribute combinations, implicit signals)
        const metadata = getDetectionMetadata(influence.attributeUsed);

        attributes.push({
          sessionId: sessionId,
          attributeName: influence.attributeUsed,
          attributeValue: 'implicit', // No explicit value, inferred from influence
          detectionMethod: metadata?.detectionMethod || 'derived',
          detectionEvidence:
            metadata?.evidence || `Implicit influence on ${influence.targetCategory}: ${influence.applicationReason}`,
          influenceRole: influence.roleType,
          categoriesInfluenced: [influence.targetCategory],
          totalBonusApplied: new Prisma.Decimal(influence.scoreImpact),
          createdAt: new Date(),
        });

        // Mark as covered to avoid duplicates
        coveredAttributes.add(influence.attributeUsed);
      }
    }

    return attributes;
  }

  /**
   * Build extracted feature data from AI feature extraction results
   *
   * Extracts AI-generated features from the explainability trace and creates
   * database records linked to the AI routing stage (stage 8).
   *
   * Only called when AI routing was used (result.aiRoutingUsed = true).
   *
   * @param result - ClassificationResult with AI feature extraction data
   * @param stageRecords - Created classification stages with IDs
   * @returns Array of extracted feature records for database insertion
   */
  private buildExtractedFeatureData(
    result: ClassificationResult,
    stageRecords: Array<{ stageId: bigint; stageOrder: number }>
  ): Array<Prisma.ExtractedFeatureCreateManyInput> {
    const features: Array<Prisma.ExtractedFeatureCreateManyInput> = [];

    // Find the AI routing stage (stage 8) to associate features with
    const aiRoutingStage = stageRecords.find((stage) => stage.stageOrder === 8);
    if (!aiRoutingStage) {
      console.warn('AI routing stage not found in stage records, skipping feature extraction persistence');
      return features;
    }

    // Extract AI feature extraction data from explainability trace
    const aiResponse = result.explainabilityTrace?.aiRouting?.aiResponse;
    if (!aiResponse?.extractedFeatures) {
      // No AI features to persist (AI routing may have skipped feature extraction)
      return features;
    }

    const extractedFeatures = aiResponse.extractedFeatures as {
      semanticIntent?: {
        primaryPurpose?: string;
        actionRequired?: string;
        urgencyLevel?: string;
      };
      categoryEnhancements?: Record<
        string,
        {
          applies: boolean;
          confidenceBoost: number;
          evidence?: {
            quotedPhrases?: string[];
            keywords?: string[];
            reasoning?: string;
          };
        }
      >;
    };

    // Extract semantic intent features
    if (extractedFeatures.semanticIntent) {
      const intent = extractedFeatures.semanticIntent;

      if (intent.primaryPurpose) {
        features.push({
          stageId: aiRoutingStage.stageId,
          name: 'semantic_intent_primary_purpose',
          value: intent.primaryPurpose,
          importance: new Prisma.Decimal(0.8), // High importance for primary purpose
          evidenceSnippet: null,
          createdAt: new Date(),
        });
      }

      if (intent.actionRequired) {
        features.push({
          stageId: aiRoutingStage.stageId,
          name: 'semantic_intent_action_required',
          value: intent.actionRequired,
          importance: new Prisma.Decimal(0.7),
          evidenceSnippet: null,
          createdAt: new Date(),
        });
      }

      if (intent.urgencyLevel) {
        features.push({
          stageId: aiRoutingStage.stageId,
          name: 'semantic_intent_urgency_level',
          value: intent.urgencyLevel,
          importance: new Prisma.Decimal(0.6),
          evidenceSnippet: null,
          createdAt: new Date(),
        });
      }
    }

    // Extract category enhancement features
    if (extractedFeatures.categoryEnhancements) {
      for (const [category, enhancement] of Object.entries(extractedFeatures.categoryEnhancements)) {
        if (enhancement.applies && enhancement.confidenceBoost > 0) {
          // Create a feature record for this category enhancement
          const evidenceSnippet =
            enhancement.evidence?.quotedPhrases && enhancement.evidence.quotedPhrases.length > 0
              ? enhancement.evidence.quotedPhrases.slice(0, 3).join(' | ') // First 3 quoted phrases
              : enhancement.evidence?.reasoning || null;

          features.push({
            stageId: aiRoutingStage.stageId,
            name: `category_enhancement_${category}`,
            value: `boost:${enhancement.confidenceBoost}`,
            importance: new Prisma.Decimal(Math.min(enhancement.confidenceBoost / 100, 1.0)), // Normalize to 0-1
            evidenceSnippet: evidenceSnippet ? evidenceSnippet.substring(0, 500) : null, // Limit length
            createdAt: new Date(),
          });

          // If there are keywords, create a separate feature for them
          if (enhancement.evidence?.keywords && enhancement.evidence.keywords.length > 0) {
            features.push({
              stageId: aiRoutingStage.stageId,
              name: `category_keywords_${category}`,
              value: enhancement.evidence.keywords.slice(0, 10).join(', '), // First 10 keywords
              importance: new Prisma.Decimal(0.5),
              evidenceSnippet: null,
              createdAt: new Date(),
            });
          }
        }
      }
    }

    return features;
  }

  /**
   * Get category ID from category code
   *
   * Uses cached category lookup for performance. Cache is initialized
   * on first use and persists for the lifetime of the repository instance.
   *
   * @param code - Category code (e.g., 'finance', 'personal')
   * @returns Category ID from database
   * @throws {Error} If category code not found in database
   */
  private async getCategoryIdFromCode(code: string): Promise<number> {
    // Initialize cache on first use
    if (this.categoryCache === null) {
      await this.initializeCategoryCache();
    }

    const categoryId = this.categoryCache!.get(code);
    if (categoryId === undefined) {
      throw new Error(
        `Category code '${code}' not found in database. Available categories: ${Array.from(this.categoryCache!.keys()).join(', ')}`
      );
    }

    return categoryId;
  }

  /**
   * Close the Prisma client connection
   *
   * Only closes if using default Prisma instance (not externally provided).
   */
  async close(): Promise<void> {
    if (this.ownsPrisma) {
      await this.prisma.$disconnect();
    }
  }
}

